params.script:
// Script Template: condition_group
// 入力モジュールの出力値をグループ番号に分類（多段分岐用）
// プレースホルダー: OpenAI_診療科 = 入力元モジュール名（OpenAI モジュール）
// プレースホルダー: {"登録なし": "1", "救急外来": "1", "心臓リハビリ外来": "1", "歯科口腔外科": "1", "内科": "1", "呼吸器": "1", "心臓": "1", "術前": "1", "肝臓": "1", "膵臓": "1", "other": "2"} = 値→グループ番号の JSON オブジェクト
// プレースホルダー: 2 = マッピングに該当しない場合のデフォルトグループ番号
// 出力: グループ番号文字列（"1", "2", ... "10"）

var input = $runner.getModuleResult("OpenAI_診療科");
var mapping = {"登録なし": "1", "救急外来": "1", "心臓リハビリ外来": "1", "歯科口腔外科": "1", "内科": "1", "呼吸器": "1", "心臓": "1", "術前": "1", "肝臓": "1", "膵臓": "1", "other": "2"};
var group = mapping[input];
if (!group) { group = "2"; }
$runner.setResult(group);
